import base64
from io import BytesIO
from PIL import Image

# Exemplo de string de imagem base64
base64_string = "data:image/webp;base64,"
# Decodifica a string de base64 em dados brutos
image_data = base64.b64decode(base64_string.split(',')[1])
# Carrega a imagem decodificada em um objeto de imagem com a biblioteca Pillow
img = Image.open(BytesIO(image_data))

# Calcula as dimensões do corte com a proporção 16:9
width, height = img.size
if width / height > 16 / 9:
    new_width = int(height * 16 / 9)
    new_height = height
else:
    new_width = width
    new_height = int(width * 9 / 16)

# Calcula as coordenadas do retângulo de corte
left = (width - new_width) / 2
top = (height - new_height) / 2
right = left + new_width
bottom = top + new_height
crop_rectangle = (left, top, right, bottom)

# Recorta a imagem na proporção 16:9
cropped_img = img.crop(crop_rectangle)

# Reduz o tamanho da imagem em 30%
new_width = int(cropped_img.size[0] * 0.7)
new_height = int(cropped_img.size[1] * 0.7)
#cropped_img.thumbnail((new_width, new_height), Image.ANTIALIAS)
cropped_img.thumbnail((new_width, new_height), Image.Resampling.LANCZOS)


# Salva a imagem recortada e reduzida em um arquivo
cropped_img.save("img/imagem_recortada_reduzida.jpg")